shortcuts.codeOnPrepare:
if (!variables.get('base_url') || variables.get('base_url') === 'https://YOUR-NGROK-URL') {
  alert('⚠️ Please set your ngrok URL first!\n\nEdit the base_url variable in HTTP Shortcuts settings.');
  abort();
}

shortcuts.codeOnSuccess:
// Parse the initial job response
const jobResponse = JSON.parse(response.body);
const jobId = jobResponse.jobId;

if (!jobId) {
  // Duplicate detected - server returned existing result
  if (jobResponse.result) {
    const recipe = jobResponse.result;
    showDialog(recipe.title + '\n\n' + '⚡ Already extracted (from cache)' + '\n\n🥘 ' + (recipe.ingredients ? recipe.ingredients.length : 0) + ' ingredients · ' + (recipe.steps ? recipe.steps.length : 0) + ' steps');
    clipboard.copy(JSON.stringify(recipe, null, 2));
  } else {
    alert('Unexpected response: ' + response.body);
  }
  return;
}

toast('🚀 Job queued: ' + jobId);

// Poll every 6 seconds, up to 50 times (5 minutes)
const baseUrl = variables.get('base_url');
let attempts = 0;
let status = 'pending';
let job = null;

while (attempts < 50) {
  wait(6000);
  attempts++;

  const statusRes = http.get(baseUrl + '/api/jobs/' + jobId);
  if (statusRes.statusCode !== 200) {
    toast('⚠️ Status check failed (attempt ' + attempts + ')');
    continue;
  }

  job = JSON.parse(statusRes.body);
  status = job.status;

  if (status === 'completed') break;
  if (status === 'failed') break;

  toast('⏳ ' + status + '... (attempt ' + attempts + ')');
}

if (status === 'completed' && job && job.result) {
  const recipe = job.result;
  const title = recipe.title || 'Untitled Recipe';
  const ingredients = recipe.ingredients ? recipe.ingredients.length : 0;
  const steps = recipe.steps ? recipe.steps.length : 0;
  const cuisine = recipe.cuisineType || '';

  clipboard.copy(JSON.stringify(recipe, null, 2));

  showDialog(
    '✅ ' + title + '\n\n' +
    (cuisine ? '🌍 ' + cuisine + '\n' : '') +
    '🥘 ' + ingredients + ' ingredients\n' +
    '📋 ' + steps + ' steps\n\n' +
    '📋 Full JSON copied to clipboard!'
  );
} else if (status === 'failed') {
  const errMsg = job && job.error ? job.error : 'Unknown error';
  alert('❌ Extraction failed:\n' + errMsg);
} else {
  alert('⏰ Timed out after ' + attempts + ' attempts. Check manually with Job ID:\n' + jobId);
}
